import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState('');
  const [showOtpInput, setShowOtpInput] = useState(false);
  const [schemes, setSchemes] = useState([]);
  const [activeTab, setActiveTab] = useState('schemes');
  const [isListening, setIsListening] = useState(false);
  const [voiceQuery, setVoiceQuery] = useState('');
  const [voiceResponse, setVoiceResponse] = useState('');
  const [selectedLanguage, setSelectedLanguage] = useState('hindi');
  const [searchTerm, setSearchTerm] = useState('');

  const languages = ['हिन्दी', 'English', 'ಕನ್ನಡ', 'తెలుగు', 'தமிழ்', 'മലയാളം', 'বাংলা', 'मराठी', 'ગુજરાતી', 'ଓଡ଼ିଆ'];

  useEffect(() => {
    fetchSchemes();
  }, []);

  const fetchSchemes = async () => {
    try {
      const response = await fetch('/api/schemes');
      const data = await response.json();
      if (data.success) setSchemes(data.schemes);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const sendOTP = async () => {
    try {
      const response = await fetch('/api/auth/send-otp', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ mobileNumber })
      });
      const data = await response.json();
      if (data.success) {
        setShowOtpInput(true);
        alert('OTP sent! Check backend terminal');
      }
    } catch (error) {
      alert('Error sending OTP');
    }
  };

  const verifyOTP = async () => {
    try {
      const response = await fetch('/api/auth/verify-otp', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ mobileNumber, otp })
      });
      const data = await response.json();
      if (data.success) {
        setIsLoggedIn(true);
        alert('Welcome to JanSahay! 🇮🇳');
      } else {
        alert('Invalid OTP');
      }
    } catch (error) {
      alert('Error verifying OTP');
    }
  };

  // Voice Recognition
  const startListening = () => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.webkitSpeechRecognition || window.SpeechRecognition;
      const recognition = new SpeechRecognition();
      recognition.lang = selectedLanguage === 'hindi' ? 'hi-IN' : 'en-IN';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onstart = () => {
        setIsListening(true);
        setVoiceResponse('🎤 Listening...');
      };

      recognition.onresult = async (event) => {
        const query = event.results[0][0].transcript;
        setVoiceQuery(query);
        setIsListening(false);
        setVoiceResponse('🤔 Thinking...');
        
        // Send to backend
        try {
          const response = await fetch('/api/voice/assistant', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ query, language: selectedLanguage })
          });
          const data = await response.json();
          setVoiceResponse(data.response);
          
          // Speak the response
          const utterance = new SpeechSynthesisUtterance(data.response);
          utterance.lang = selectedLanguage === 'hindi' ? 'hi-IN' : 'en-IN';
          window.speechSynthesis.speak(utterance);
        } catch (error) {
          setVoiceResponse('Sorry, something went wrong');
        }
      };

      recognition.onerror = () => {
        setIsListening(false);
        setVoiceResponse('Please try again');
      };

      recognition.start();
    } else {
      alert('Voice recognition not supported in this browser. Please use Chrome.');
    }
  };

  const filteredSchemes = schemes.filter(scheme =>
    scheme.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="tricolor-bg"></div>
        <div className="login-card">
          <div className="ashoka-chakra">🔄</div>
          <h1>🇮🇳 JanSahay</h1>
          <p className="tagline">सरकारी योजना सहायक | Government Scheme Assistant</p>
          <h2>Secure Sign In</h2>
          <div className="input-group">
            <input
              type="tel"
              placeholder="Mobile Number"
              value={mobileNumber}
              onChange={(e) => setMobileNumber(e.target.value)}
            />
          </div>
          {!showOtpInput ? (
            <button className="login-btn" onClick={sendOTP}>Send Secure OTP</button>
          ) : (
            <>
              <div className="input-group">
                <input
                  type="text"
                  placeholder="Enter OTP"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value)}
                />
              </div>
              <button className="login-btn" onClick={verifyOTP}>Verify & Login</button>
            </>
          )}
          <div className="emergency-footer">
            <span>🚓 100</span>
            <span>🚑 102</span>
            <span>👩 1091</span>
            <span>👶 1098</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="app">
      {/* Tricolor Header */}
      <div className="tricolor-header">
        <div className="saffron"></div>
        <div className="white"></div>
        <div className="green"></div>
      </div>

      {/* Main Header */}
      <header className="header">
        <div className="logo">
          <span className="ashoka">🔄</span>
          <h1>JanSahay <span className="govt">GOVERNMENT OF INDIA</span></h1>
        </div>
        <div className="language-selector">
          {languages.slice(0, 5).map(lang => (
            <button
              key={lang}
              className={`lang-btn ${selectedLanguage === lang.toLowerCase() ? 'active' : ''}`}
              onClick={() => setSelectedLanguage(lang.toLowerCase())}
            >
              {lang}
            </button>
          ))}
        </div>
      </header>

      {/* Navigation Bar */}
      <nav className="nav-bar">
        <button className={`nav-item ${activeTab === 'schemes' ? 'active' : ''}`} onClick={() => setActiveTab('schemes')}>
          📋 All Schemes
        </button>
        <button className={`nav-item ${activeTab === 'voice' ? 'active' : ''}`} onClick={() => setActiveTab('voice')}>
          🎤 Voice Assistant
        </button>
        <button className="nav-item" onClick={() => setActiveTab('eligibility')}>
          ✅ Check Eligibility
        </button>
        <button className="nav-item" onClick={() => setActiveTab('officers')}>
          👮 Find Officers
        </button>
      </nav>

      {/* Search Bar */}
      <div className="search-section">
        <input
          type="text"
          placeholder="🔍 Search schemes by name, category, or benefits..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {/* Main Content */}
      <main className="main-content">
        {activeTab === 'schemes' && (
          <div className="schemes-container">
            <h2>🇮🇳 Government Schemes <span className="scheme-count">({filteredSchemes.length} schemes)</span></h2>
            <div className="schemes-grid">
              {filteredSchemes.map((scheme, index) => (
                <div key={index} className="scheme-card">
                  <div className="scheme-icon">
                    {scheme.category === 'health' && '🏥'}
                    {scheme.category === 'housing' && '🏠'}
                    {scheme.category === 'women' && '👩'}
                    {scheme.category === 'business' && '💼'}
                    {scheme.category === 'farmer' && '🌾'}
                    {scheme.category === 'education' && '📚'}
                  </div>
                  <h3>{scheme.name}</h3>
                  <span className={`category-badge ${scheme.category}`}>
                    {scheme.category === 'health' && '🏥 Health'}
                    {scheme.category === 'housing' && '🏠 Housing'}
                    {scheme.category === 'women' && '👩 Women & Child'}
                    {scheme.category === 'business' && '💼 Business'}
                    {scheme.category === 'farmer' && '🌾 Farmer'}
                    {scheme.category === 'education' && '📚 Education'}
                  </span>
                  {scheme.benefits && scheme.benefits.length > 0 && (
                    <div className="benefits">
                      <strong>Benefits:</strong>
                      <ul>
                        {scheme.benefits.slice(0, 2).map((b, i) => <li key={i}>{b}</li>)}
                      </ul>
                    </div>
                  )}
                  <button className="check-btn">Check Eligibility →</button>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'voice' && (
          <div className="voice-container">
            <div className="voice-card">
              <div className="voice-icon" onClick={startListening}>
                {isListening ? '🎤🔴' : '🎤'}
              </div>
              <p className="voice-instruction">
                {isListening ? 'Listening... Speak now!' : 'Click the mic and ask about schemes'}
              </p>
              {voiceQuery && (
                <div className="voice-query">
                  <strong>You said:</strong>
                  <p>{voiceQuery}</p>
                </div>
              )}
              {voiceResponse && (
                <div className="voice-response">
                  <strong>JanSahay Assistant:</strong>
                  <p>{voiceResponse}</p>
                </div>
              )}
              <div className="voice-examples">
                <p>Try asking:</p>
                <button onClick={() => setVoiceQuery('Tell me about PM-KISAN scheme')}>🌾 PM-KISAN scheme</button>
                <button onClick={() => setVoiceQuery('Health schemes for families')}>🏥 Health schemes</button>
                <button onClick={() => setVoiceQuery('Schemes for women')}>👩 Women schemes</button>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="footer">
        <div className="footer-content">
          <div className="emergency">
            <h4>📞 Emergency Helplines</h4>
            <p>🚓 Police: 100 | 🚑 Ambulance: 102 | 👩 Women Helpline: 1091 | 👶 Child Helpline: 1098 | 🆘 Emergency: 112</p>
          </div>
          <div className="copyright">
            <p>© 2026 JanSahay - Government of India | सरकारी योजना सहायक</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

export default App;
